# lib/blog/sanitizer.ex
defmodule Blog.Sanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content to prevent XSS attacks.
  Allows safe formatting tags while stripping dangerous elements.
  """

  # Define a custom scrubber that allows rich formatting but blocks scripts
  defmodule RichTextScrubber do
    require HtmlSanitizeEx.Scrubber.Meta
    alias HtmlSanitizeEx.Scrubber.Meta

    # Allow safe formatting tags
    Meta.allow_tag_with_these_attributes("p", ["class"])
    Meta.allow_tag_with_these_attributes("br", [])
    Meta.allow_tag_with_these_attributes("strong", [])
    Meta.allow_tag_with_these_attributes("b", [])
    Meta.allow_tag_with_these_attributes("em", [])
    Meta.allow_tag_with_these_attributes("i", [])
    Meta.allow_tag_with_these_attributes("u", [])
    Meta.allow_tag_with_these_attributes("s", [])
    Meta.allow_tag_with_these_attributes("ul", ["class"])
    Meta.allow_tag_with_these_attributes("ol", ["class"])
    Meta.allow_tag_with_these_attributes("li", [])
    Meta.allow_tag_with_these_attributes("h1", ["class"])
    Meta.allow_tag_with_these_attributes("h2", ["class"])
    Meta.allow_tag_with_these_attributes("h3", ["class"])
    Meta.allow_tag_with_these_attributes("h4", ["class"])
    Meta.allow_tag_with_these_attributes("blockquote", ["class"])
    Meta.allow_tag_with_these_attributes("pre", ["class"])
    Meta.allow_tag_with_these_attributes("code", ["class"])
    Meta.allow_tag_with_these_attributes("span", ["class"])
    Meta.allow_tag_with_these_attributes("div", ["class"])
    Meta.allow_tag_with_these_attributes("table", ["class"])
    Meta.allow_tag_with_these_attributes("thead", [])
    Meta.allow_tag_with_these_attributes("tbody", [])
    Meta.allow_tag_with_these_attributes("tr", [])
    Meta.allow_tag_with_these_attributes("th", ["class"])
    Meta.allow_tag_with_these_attributes("td", ["class"])

    # Allow links with safe attributes only (no javascript: URIs)
    Meta.allow_tag_with_uri_attributes("a", ["href"], ["http", "https", "mailto"])
    Meta.allow_tag_with_these_attributes("a", ["title", "class", "rel", "target"])

    # Allow images with safe src attributes only
    Meta.allow_tag_with_uri_attributes("img", ["src"], ["http", "https"])
    Meta.allow_tag_with_these_attributes("img", ["alt", "title", "class", "width", "height"])

    # Strip everything else (including script, style, iframe, object, embed, form, input, etc.)
    Meta.strip_everything_not_covered()
  end

  @doc """
  Sanitizes HTML content, allowing safe rich-text tags while removing
  all dangerous elements like <script>, event handlers, javascript: URIs, etc.
  """
  def sanitize_rich_text(nil), do: ""
  def sanitize_rich_text(html) when is_binary(html) do
    HtmlSanitizeEx.Scrubber.scrub(html, RichTextScrubber)
  end
end

# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset
  alias Blog.Sanitizer

  schema "posts" do
    field :title, :string
    field :content, :string
    field :sanitized_content, :string
    field :author_id, :id

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content, :author_id])
    |> validate_required([:title, :content])
    |> validate_length(:title, min: 1, max: 255)
    |> validate_length(:content, min: 1, max: 100_000)
    |> sanitize_content()
  end

  # Sanitize content at the changeset level before it hits the database
  defp sanitize_content(changeset) do
    case get_change(changeset, :content) do
      nil -> changeset
      content ->
        sanitized = Sanitizer.sanitize_rich_text(content)
        put_change(changeset, :sanitized_content, sanitized)
    end
  end
end

# lib/blog_web/helpers/safe_html.ex
defmodule BlogWeb.SafeHTML do
  @moduledoc """
  Helper functions for safely rendering user-generated HTML content.
  NEVER use raw() directly with unsanitized user input.
  """

  alias Blog.Sanitizer

  def safe_rich_html(nil), do: {:safe, ""}
  def safe_rich_html(content) when is_binary(content) do
    content
    |> Sanitizer.sanitize_rich_text()
    |> Phoenix.HTML.raw()
  end
end

