# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts
  import BlogWeb.SafeHTML

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, :posts, posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-4xl font-bold mb-8">Blog Posts</h1>

      <div class="space-y-8">
        <article :for={post <- @posts} class="border-b border-gray-200 pb-8">
          <h2 class="text-2xl font-semibold mb-2">
            <.link navigate={~p"/posts/#{post.id}"} class="text-blue-700 hover:underline">
              <%= post.title %>
            </.link>
          </h2>
          <div class="text-gray-500 text-sm mb-4">
            Published <%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %>
          </div>
          <div class="prose max-w-none line-clamp-3">
            <%!-- Render a sanitized preview of the content --%>
            <%= safe_rich_html(truncate_html(post.sanitized_content, 300)) %>
          </div>
        </article>
      </div>
    </div>
    """
  end

  defp truncate_html(nil, _length), do: ""
  defp truncate_html(html, length) when is_binary(html) do
    # Strip tags for preview, then truncate safely
    text = HtmlSanitizeEx.strip_tags(html)
    if String.length(text) > length do
      String.slice(text, 0, length) <> "..."
    else
      text
    end
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})

    {:ok,
     socket
     |> assign(:page_title, "New Post")
     |> assign(:form, to_form(changeset))}
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, :form, to_form(changeset))}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post created successfully!")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply, assign(socket, :form, to_form(changeset))}
    end
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-4xl font-bold mb-8"><%= @page_title %></h1>

      <.form for={@form} phx-change="validate" phx-submit="save" class="space-y-6">
        <div>
          <.input field={@form[:title]} type="text" label="Title" />
        </div>

        <div>
          <label class="block text-sm font-semibold mb-2">Content (HTML supported)</label>
          <textarea
            name={@form[:content].name}
            id={@form[:content].id}
            rows="20"
            class="w-full rounded-lg border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 font-mono text-sm"
            phx-debounce="500"
          ><%= Phoenix.HTML.Form.normalize_value("textarea", @form[:content].value) %></textarea>
          <p class="mt-2 text-sm text-gray-500">
            Allowed HTML tags: p, strong, em, ul, ol, li, h1-h4, blockquote, pre, code, a, img, table.
            Script tags and event handlers are automatically removed for security.
          </p>
        </div>

        <div>
          <button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700">
            Publish Post
          </button>
        </div>
      </.form>
    </div>
    """
  end
end

# lib/blog/posts.ex
defmodule Blog.Posts do
  import Ecto.Query
  alias Blog.Repo
  alias Blog.Posts.Post

  def list_posts do
    Post
    |> order_by(desc: :inserted_at)
    |> Repo.all()
  end

  def get_post!(id), do: Repo.get!(Post, id)

  def create_post(attrs \\ %{}) do
    %Post{}
    |> Post.changeset(attrs)
    |> Repo.insert()
  end

  def update_post(%Post{} = post, attrs) do
    post
    |> Post.changeset(attrs)
    |> Repo.update()
  end

  def change_post(%Post{} = post, attrs \\ %{}) do
    Post.changeset(post, attrs)
  end
end

